"use strict";(self.webpackChunk_infrawatch_docs=self.webpackChunk_infrawatch_docs||[]).push([[747],{6371:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"mainSidebar":[{"type":"link","label":"Introduction","href":"/infrawatch/","docId":"intro","unlisted":false},{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","label":"Installation","href":"/infrawatch/getting-started/installation","docId":"getting-started/installation","unlisted":false},{"type":"link","label":"Configuration","href":"/infrawatch/getting-started/configuration","docId":"getting-started/configuration","unlisted":false}],"collapsible":true},{"type":"category","label":"Architecture","items":[{"type":"link","label":"Architecture Overview","href":"/infrawatch/architecture/overview","docId":"architecture/overview","unlisted":false},{"type":"link","label":"Agent Architecture","href":"/infrawatch/architecture/agent","docId":"architecture/agent","unlisted":false},{"type":"link","label":"Ingest Service","href":"/infrawatch/architecture/ingest","docId":"architecture/ingest","unlisted":false},{"type":"link","label":"Deployment Profiles","href":"/infrawatch/architecture/deployment-profiles","docId":"architecture/deployment-profiles","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Features","items":[{"type":"link","label":"Hosts & Inventory","href":"/infrawatch/features/hosts","docId":"features/hosts","unlisted":false},{"type":"link","label":"Host Groups","href":"/infrawatch/features/host-groups","docId":"features/host-groups","unlisted":false},{"type":"link","label":"Monitoring","href":"/infrawatch/features/monitoring","docId":"features/monitoring","unlisted":false},{"type":"link","label":"Certificate Management","href":"/infrawatch/features/certificates","docId":"features/certificates","unlisted":false},{"type":"link","label":"Alerts","href":"/infrawatch/features/alerts","docId":"features/alerts","unlisted":false},{"type":"link","label":"Notifications","href":"/infrawatch/features/notifications","docId":"features/notifications","unlisted":false},{"type":"link","label":"Reports","href":"/infrawatch/features/reports","docId":"features/reports","unlisted":false},{"type":"link","label":"Terminal","href":"/infrawatch/features/terminal","docId":"features/terminal","unlisted":false},{"type":"link","label":"Service Accounts & Identity","href":"/infrawatch/features/service-accounts","docId":"features/service-accounts","unlisted":false},{"type":"link","label":"Tasks & Runbooks","href":"/infrawatch/features/tasks","docId":"features/tasks","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Deployment","items":[{"type":"link","label":"Docker Compose Deployment","href":"/infrawatch/deployment/docker-compose","docId":"deployment/docker-compose","unlisted":false},{"type":"link","label":"Air-Gap Deployment","href":"/infrawatch/deployment/air-gap","docId":"deployment/air-gap","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"architecture/agent":{"id":"architecture/agent","title":"Agent Architecture","description":"The Infrawatch agent is a statically compiled Go binary. It has no runtime dependencies \u2014 just copy the binary to a host and run it. It is designed to work in fully air-gapped environments.","sidebar":"mainSidebar"},"architecture/deployment-profiles":{"id":"architecture/deployment-profiles","title":"Deployment Profiles","description":"Infrawatch ships with three deployment profiles, each targeting a different scale. All profiles use the same codebase \u2014 only the infrastructure backing them changes.","sidebar":"mainSidebar"},"architecture/ingest":{"id":"architecture/ingest","title":"Ingest Service","description":"The ingest service is a stateless gRPC server that sits between the agents and the database. It is the only service that agents communicate with directly \u2014 the web app reads from the same database and never talks to ingest in the request path.","sidebar":"mainSidebar"},"architecture/overview":{"id":"architecture/overview","title":"Architecture Overview","description":"Infrawatch is a monorepo composed of several independently deployable services. This page describes the high-level architecture and how data flows through the system.","sidebar":"mainSidebar"},"deployment/air-gap":{"id":"deployment/air-gap","title":"Air-Gap Deployment","description":"Infrawatch is designed to work in fully air-gapped environments \u2014 no internet access is required for any core feature, including agent registration, metrics collection, alerting, and agent binary distribution.","sidebar":"mainSidebar"},"deployment/docker-compose":{"id":"deployment/docker-compose","title":"Docker Compose Deployment","description":"The recommended way to run Infrawatch in production is via docker-compose.single.yml. This deploys the full stack (web, ingest, database) on a single host using pre-built images from GHCR.","sidebar":"mainSidebar"},"features/alerts":{"id":"features/alerts","title":"Alerts","description":"Alert rules define the conditions under which Infrawatch generates a notification. Rules are evaluated by the alerts consumer as metrics and check results arrive from the queue.","sidebar":"mainSidebar"},"features/certificates":{"id":"features/certificates","title":"Certificate Management","description":"Infrawatch discovers TLS certificates on your hosts automatically and tracks their expiry dates \u2014 so you know about certificate expirations before they cause outages.","sidebar":"mainSidebar"},"features/host-groups":{"id":"features/host-groups","title":"Host Groups","description":"Host Groups let you organise hosts into logical collections \u2014 by environment (production / staging), team ownership, geography, or any other dimension that makes sense for your organisation.","sidebar":"mainSidebar"},"features/hosts":{"id":"features/hosts","title":"Hosts & Inventory","description":"The Hosts page is the primary inventory view in Infrawatch. It shows every server that has registered an agent, along with real-time status, recent vitals, and quick access to all host-level tooling.","sidebar":"mainSidebar"},"features/monitoring":{"id":"features/monitoring","title":"Monitoring","description":"Infrawatch collects system metrics from every agent and lets you define health checks that run on a schedule. Metrics are stored in TimescaleDB and visualised as time-series charts.","sidebar":"mainSidebar"},"features/notifications":{"id":"features/notifications","title":"Notifications","description":"Infrawatch supports multiple notification channels. Each alert rule specifies which channels its notifications are routed to.","sidebar":"mainSidebar"},"features/reports":{"id":"features/reports","title":"Reports","description":"The Reports section provides fleet-wide views that aggregate data across all hosts. Currently the primary report is the Software Inventory report.","sidebar":"mainSidebar"},"features/service-accounts":{"id":"features/service-accounts","title":"Service Accounts & Identity","description":"Infrawatch tracks the users and service accounts present on your hosts \u2014 including domain accounts synced from LDAP/Active Directory. This gives you a fleet-wide view of who has access to what.","sidebar":"mainSidebar"},"features/tasks":{"id":"features/tasks","title":"Tasks & Runbooks","description":"The Tasks feature lets you run scripts on hosts directly from the Infrawatch UI, and Runbooks provide a way to define reusable, multi-step operational procedures.","sidebar":"mainSidebar"},"features/terminal":{"id":"features/terminal","title":"Terminal","description":"Infrawatch provides a persistent, browser-based terminal that gives you shell access to any host that has an active agent \u2014 without needing SSH configured or a VPN connection.","sidebar":"mainSidebar"},"getting-started/configuration":{"id":"getting-started/configuration","title":"Configuration","description":"All Infrawatch configuration is via environment variables. There are no config files for the web app or ingest service in production \u2014 just set env vars in your .env file or compose config.","sidebar":"mainSidebar"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation","description":"This guide walks you through getting Infrawatch running \u2014 from zero to a real agent showing up as online in the host inventory.","sidebar":"mainSidebar"},"intro":{"id":"intro","title":"Introduction","description":"Infrawatch is an open-source infrastructure monitoring and tooling platform built for corporate engineering teams and individual operators who need full control over their observability stack.","sidebar":"mainSidebar"}}}}')}}]);